#include<bits/stdc++.h>
using namespace std;
long long n,k;
long long a[2005000],s[2005000];
long long id[2005000],lst;
int main(){
    cin>>n>>k;
    for(int i=1;i<=n;i++) cin>>a[i],s[i]=s[i-1]^a[i];
    memset(id,-1,sizeof id);
    id[0]=0;
    long long ans=0;
    for(int r=1;r<=n;r++){
        long long x=s[r]^k;
        if(id[x]>=lst){
            ans++;
            lst=r;
        }
        id[s[r]]=r;
    }
    cout<<ans;
    return 0;
}
